import asyncio
import websockets
import json
import uuid
from dataclasses import dataclass, field, asdict
from typing import Dict, List, Optional, Set
from enum import Enum
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class ItemRarity(Enum):
    COMMON = "common"
    UNCOMMON = "uncommon"
    RARE = "rare"
    EPIC = "epic"
    LEGENDARY = "legendary"


@dataclass
class Item:
    item_id: str
    name: str
    rarity: ItemRarity
    quantity: int = 1
    tradeable: bool = True
    
    def to_dict(self):
        return {
            "item_id": self.item_id,
            "name": self.name,
            "rarity": self.rarity.value,
            "quantity": self.quantity,
            "tradeable": self.tradeable
        }


@dataclass
class Player:
    player_id: str
    username: str
    inventory: Dict[str, Item] = field(default_factory=dict)
    max_inventory_size: int = 100
    gold: int = 1000
    websocket: Optional[websockets.WebSocketServerProtocol] = None
    
    def add_item(self, item: Item) -> bool:
        if item.item_id in self.inventory:
            self.inventory[item.item_id].quantity += item.quantity
            return True
        elif len(self.inventory) < self.max_inventory_size:
            self.inventory[item.item_id] = item
            return True
        return False
    
    def remove_item(self, item_id: str, quantity: int = 1) -> bool:
        if item_id not in self.inventory:
            return False
        
        if self.inventory[item_id].quantity < quantity:
            return False
        
        self.inventory[item_id].quantity -= quantity
        if self.inventory[item_id].quantity == 0:
            del self.inventory[item_id]
        
        return True
    
    def has_item(self, item_id: str, quantity: int = 1) -> bool:
        return item_id in self.inventory and self.inventory[item_id].quantity >= quantity
    
    def get_inventory_dict(self):
        return {k: v.to_dict() for k, v in self.inventory.items()}


class TradeStatus(Enum):
    PENDING = "pending"
    ACCEPTED = "accepted"
    COMPLETED = "completed"
    CANCELLED = "cancelled"


@dataclass
class TradeOffer:
    trade_id: str
    initiator_id: str
    recipient_id: str
    initiator_items: List[Dict] = field(default_factory=list)
    recipient_items: List[Dict] = field(default_factory=list)
    initiator_gold: int = 0
    recipient_gold: int = 0
    initiator_ready: bool = False
    recipient_ready: bool = False
    status: TradeStatus = TradeStatus.PENDING
    
    def to_dict(self):
        return {
            "trade_id": self.trade_id,
            "initiator_id": self.initiator_id,
            "recipient_id": self.recipient_id,
            "initiator_items": self.initiator_items,
            "recipient_items": self.recipient_items,
            "initiator_gold": self.initiator_gold,
            "recipient_gold": self.recipient_gold,
            "initiator_ready": self.initiator_ready,
            "recipient_ready": self.recipient_ready,
            "status": self.status.value
        }


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.active_trades: Dict[str, TradeOffer] = {}
        self.player_locks: Dict[str, asyncio.Lock] = {}
        self.trade_locks: Dict[str, asyncio.Lock] = {}
        self.connected_websockets: Dict[str, websockets.WebSocketServerProtocol] = {}
        
    def get_player_lock(self, player_id: str) -> asyncio.Lock:
        if player_id not in self.player_locks:
            self.player_locks[player_id] = asyncio.Lock()
        return self.player_locks[player_id]
    
    def get_trade_lock(self, trade_id: str) -> asyncio.Lock:
        if trade_id not in self.trade_locks:
            self.trade_locks[trade_id] = asyncio.Lock()
        return self.trade_locks[trade_id]
    
    async def register_player(self, username: str, websocket) -> str:
        player_id = str(uuid.uuid4())
        player = Player(player_id=player_id, username=username, websocket=websocket)
        
        starter_items = [
            Item(str(uuid.uuid4()), "Iron Sword", ItemRarity.COMMON, 1),
            Item(str(uuid.uuid4()), "Health Potion", ItemRarity.COMMON, 5),
            Item(str(uuid.uuid4()), "Leather Armor", ItemRarity.UNCOMMON, 1),
        ]
        
        for item in starter_items:
            player.add_item(item)
        
        self.players[player_id] = player
        self.connected_websockets[player_id] = websocket
        
        logger.info(f"Player {username} registered with ID {player_id}")
        return player_id
    
    async def unregister_player(self, player_id: str):
        if player_id in self.players:
            for trade_id, trade in list(self.active_trades.items()):
                if trade.initiator_id == player_id or trade.recipient_id == player_id:
                    await self.cancel_trade(trade_id)
            
            del self.players[player_id]
            if player_id in self.connected_websockets:
                del self.connected_websockets[player_id]
            logger.info(f"Player {player_id} unregistered")
    
    async def send_message(self, player_id: str, message: dict):
        if player_id in self.connected_websockets:
            try:
                await self.connected_websockets[player_id].send(json.dumps(message))
            except Exception as e:
                logger.error(f"Error sending message to {player_id}: {e}")
    
    async def initiate_trade(self, initiator_id: str, recipient_id: str) -> Optional[str]:
        if initiator_id not in self.players or recipient_id not in self.players:
            return None
        
        for trade in self.active_trades.values():
            if (trade.initiator_id == initiator_id or trade.recipient_id == initiator_id or
                trade.initiator_id == recipient_id or trade.recipient_id == recipient_id):
                if trade.status == TradeStatus.PENDING:
                    return None
        
        trade_id = str(uuid.uuid4())
        trade = TradeOffer(
            trade_id=trade_id,
            initiator_id=initiator_id,
            recipient_id=recipient_id
        )
        
        self.active_trades[trade_id] = trade
        
        await self.send_message(initiator_id, {
            "type": "trade_initiated",
            "trade": trade.to_dict()
        })
        
        await self.send_message(recipient_id, {
            "type": "trade_request",
            "trade": trade.to_dict()
        })
        
        logger.info(f"Trade {trade_id} initiated between {initiator_id} and {recipient_id}")
        return trade_id
    
    async def add_items_to_trade(self, trade_id: str, player_id: str, items: List[Dict], gold: int = 0) -> bool:
        if trade_id not in self.active_trades:
            return False
        
        trade = self.active_trades[trade_id]
        
        if trade.status != TradeStatus.PENDING:
            return False
        
        async with self.get_trade_lock(trade_id):
            async with self.get_player_lock(player_id):
                player = self.players.get(player_id)
                if not player:
                    return False
                
                for item_data in items:
                    item_id = item_data.get("item_id")
                    quantity = item_data.get("quantity", 1)
                    
                    if not player.has_item(item_id, quantity):
                        return False
                    
                    if item_id in player.inventory and not player.inventory[item_id].tradeable:
                        return False
                
                if gold > 0 and player.gold < gold:
                    return False
                
                if player_id == trade.initiator_id:
                    trade.initiator_items = items
                    trade.initiator_gold = gold
                    trade.initiator_ready = False
                elif player_id == trade.recipient_id:
                    trade.recipient_items = items
                    trade.recipient_gold = gold
                    trade.recipient_ready = False
                else:
                    return False
                
                await self.send_message(trade.initiator_id, {
                    "type": "trade_updated",
                    "trade": trade.to_dict()
                })
                
                await self.send_message(trade.recipient_id, {
                    "type": "trade_updated",
                    "trade": trade.to_dict()
                })
                
                return True
    
    async def set_trade_ready(self, trade_id: str, player_id: str, ready: bool) -> bool:
        if trade_id not in self.active_trades:
            return False
        
        trade = self.active_trades[trade_id]
        
        if trade.status != TradeStatus.PENDING:
            return False
        
        async with self.get_trade_lock(trade_id):
            if player_id == trade.initiator_id:
                trade.initiator_ready = ready
            elif player_id == trade.recipient_id:
                trade.recipient_ready = ready
            else:
                return False
            
            await self.send_message(trade.initiator_id, {
                "type": "trade_updated",
                "trade": trade.to_dict()
            })
            
            await self.send_message(trade.recipient_id, {
                "type": "trade_updated",
                "trade": trade.to_dict()
            })
            
            if trade.initiator_ready and trade.recipient_ready:
                await self.execute_trade(trade_id)
            
            return True
    
    async def execute_trade(self, trade_id: str) -> bool:
        if trade_id not in self.active_trades:
            return False
        
        trade = self.active_trades[trade_id]
        
        async with self.get_trade_lock(trade_id):
            initiator = self.players.get(trade.initiator_id)
            recipient = self.players.get(trade.recipient_id)
            
            if not initiator or not recipient:
                await self.cancel_trade(trade_id)
                return False
            
            locks = sorted([trade.initiator_id, trade.recipient_id])
            async with self.get_player_lock(locks[0]):
                async with self.get_player_lock(locks[1]):
                    for item_data in trade.initiator_items:
                        item_id = item_data.get("item_id")
                        quantity = item_data.get("quantity", 1)
                        if not initiator.has_item(item_id, quantity):
                            await self.cancel_trade(trade_id)
                            return False
                    
                    for item_data in trade.recipient_items:
                        item_id = item_data.get("item_id")
                        quantity = item_data.get("quantity", 1)
                        if not recipient.has_item(item_id, quantity):
                            await self.cancel_trade(trade_id)
                            return False
                    
                    if initiator.gold < trade.initiator_gold or recipient.gold < trade.recipient_gold:
                        await self.cancel_trade(trade_id)
                        return False
                    
                    transferred_to_recipient = []
                    for item_data in trade.initiator_items:
                        item_id = item_data.get("item_id")
                        quantity = item_data.get("quantity", 1)
                        
                        original_item = initiator.inventory[item_id]
                        new_item = Item(
                            item_id=item_id,
                            name=original_item.name,
                            rarity=original_item.rarity,
                            quantity=quantity,
                            tradeable=original_item.tradeable
                        )
                        
                        initiator.remove_item(item_id, quantity)
                        recipient.add_item(new_item)
                        transferred_to_recipient.append(new_item)
                    
                    transferred_to_initiator = []
                    for item_data in trade.recipient_items:
                        item_id = item_data.get("item_id")
                        quantity = item_data.get("quantity", 1)
                        
                        original_item = recipient.inventory[item_id]
                        new_item = Item(
                            item_id=item_id,
                            name=original_item.name,
                            rarity=original_item.rarity,
                            quantity=quantity,
                            tradeable=original_item.tradeable
                        )
                        
                        recipient.remove_item(item_id, quantity)
                        initiator.add_item(new_item)
                        transferred_to_initiator.append(new_item)
                    
                    initiator.gold -= trade.initiator_gold
                    initiator.gold += trade.recipient_gold
                    
                    recipient.gold -= trade.recipient_gold
                    recipient.gold += trade.initiator_gold
                    
                    trade.status = TradeStatus.COMPLETED
                    
                    await self.send_message(trade.initiator_id, {
                        "type": "trade_completed",
                        "trade": trade.to_dict(),
                        "inventory": initiator.get_inventory_dict(),
                        "gold": initiator.gold
                    })
                    
                    await self.send_message(trade.recipient_id, {
                        "type": "trade_completed",
                        "trade": trade.to_dict(),
                        "inventory": recipient.get_inventory_dict(),
                        "gold": recipient.gold
                    })
                    
                    logger.info(f"Trade {trade_id} completed successfully")
                    
                    del self.active_trades[trade_id]
                    if trade_id in self.trade_locks:
                        del self.trade_locks[trade_id]
                    
                    return True
    
    async def cancel_trade(self, trade_id: str):
        if trade_id not in self.active_trades:
            return
        
        trade = self.active_trades[trade_id]
        trade.status = TradeStatus.CANCELLED
        
        await self.send_message(trade.initiator_id, {
            "type": "trade_cancelled",
            "trade_id": trade_id
        })
        
        await self.send_message(trade.recipient_id, {
            "type": "trade_cancelled",
            "trade_id": trade_id
        })
        
        logger.info(f"Trade {trade_id} cancelled")
        
        del self.active_trades[trade_id]
        if trade_id in self.trade_locks:
            del self.trade_locks[trade_id]
    
    async def transfer_item(self, from_player_id: str, to_player_id: str, item_id: str, quantity: int = 1) -> bool:
        if from_player_id not in self.players or to_player_id not in self.players:
            return False
        
        locks = sorted([from_player_id, to_player_id])
        async with self.get_player_lock(locks[0]):
            async with self.get_player_lock(locks[1]):
                from_player = self.players[from_player_id]
                to_player = self.players[to_player_id]
                
                if not from_player.has_item(item_id, quantity):
                    return False
                
                original_item = from_player.inventory[item_id]
                if not original_item.tradeable:
                    return False
                
                new_item = Item(
                    item_id=item_id,
                    name=original_item.name,
                    rarity=original_item.rarity,
                    quantity=quantity,
                    tradeable=original_item.tradeable
                )
                
                from_player.remove_item(item_id, quantity)
                to_player.add_item(new_item)
                
                await self.send_message(from_player_id, {
                    "type": "item_transferred_out",
                    "item_id": item_id,
                    "quantity": quantity,
                    "to_player": to_player_id,
                    "inventory": from_player.get_inventory_dict()
                })
                
                await self.send_message(to_player_id, {
                    "type": "item_transferred_in",
                    "item_id": item_id,
                    "quantity": quantity,
                    "from_player": from_player_id,
                    "inventory": to_player.get_inventory_dict()
                })
                
                logger.info(f"Item {item_id} (x{quantity}) transferred from {from_player_id} to {to_player_id}")
                return True
    
    async def get_inventory(self, player_id: str) -> Optional[Dict]:
        if player_id not in self.players:
            return None
        
        async with self.get_player_lock(player_id):
            player = self.players[player_id]
            return {
                "inventory": player.get_inventory_dict(),
                "gold": player.gold
            }
    
    async def handle_client(self, websocket, path):
        player_id = None
        try:
            async for message in websocket:
                try:
                    data = json.loads(message)
                    msg_type = data.get("type")
                    
                    if msg_type == "register":
                        username = data.get("username", f"Player_{uuid.uuid4().hex[:8]}")
                        player_id = await self.register_player(username, websocket)
                        await websocket.send(json.dumps({
                            "type": "registered",
                            "player_id": player_id,
                            "username": self.players[player_id].username,
                            "inventory": self.players[player_id].get_inventory_dict(),
                            "gold": self.players[player_id].gold
                        }))
                    
                    elif msg_type == "get_inventory":
                        pid = data.get("player_id", player_id)
                        inv_data = await self.get_inventory(pid)
                        if inv_data:
                            await websocket.send(json.dumps({
                                "type": "inventory",
                                **inv_data
                            }))
                    
                    elif msg_type == "initiate_trade":
                        initiator_id = data.get("initiator_id", player_id)
                        recipient_id = data.get("recipient_id")
                        trade_id = await self.initiate_trade(initiator_id, recipient_id)
                        if trade_id:
                            await websocket.send(json.dumps({
                                "type": "trade_initiated",
                                "trade_id": trade_id
                            }))
                        else:
                            await websocket.send(json.dumps({
                                "type": "error",
                                "message": "Unable to initiate trade"
                            }))
                    
                    elif msg_type == "add_items_to_trade":
                        trade_id = data.get("trade_id")
                        pid = data.get("player_id", player_id)
                        items = data.get("items", [])
                        gold = data.get("gold", 0)
                        success = await self.add_items_to_trade(trade_id, pid, items, gold)
                        await websocket.send(json.dumps({
                            "type": "items_added" if success else "error",
                            "trade_id": trade_id,
                            "success": success
                        }))
                    
                    elif msg_type == "set_trade_ready":
                        trade_id = data.get("trade_id")
                        pid = data.get("player_id", player_id)
                        ready = data.get("ready", True)
                        success = await self.set_trade_ready(trade_id, pid, ready)
                        await websocket.send(json.dumps({
                            "type": "ready_status_updated" if success else "error",
                            "trade_id": trade_id,
                            "success": success
                        }))
                    
                    elif msg_type == "cancel_trade":
                        trade_id = data.get("trade_id")
                        await self.cancel_trade(trade_id)
                    
                    elif msg_type == "transfer_item":
                        from_id = data.get("from_player_id", player_id)
                        to_id = data.get("to_player_id")
                        item_id = data.get("item_id")
                        quantity = data.get("quantity", 1)
                        success = await self.transfer_item(from_id, to_id, item_id, quantity)
                        await websocket.send(json.dumps({
                            "type": "transfer_result",
                            "success": success
                        }))
                    
                    elif msg_type == "get_players":
                        players_list = [
                            {"player_id": pid, "username": p.username}
                            for pid, p in self.players.items()
                        ]
                        await websocket.send(json.dumps({
                            "type": "players_list",
                            "players": players_list
                        }))
                
                except json.JSONDecodeError:
                    await websocket.send(json.dumps({
                        "type": "error",
                        "message": "Invalid JSON"
                    }))
                except Exception as e:
                    logger.error(f"Error handling message: {e}")
                    await websocket.send(json.dumps({
                        "type": "error",
                        "message": str(e)
                    }))
        
        except websockets.exceptions.ConnectionClosed:
            logger.info(f"Connection closed for player {player_id}")
        finally:
            if player_id:
                await self.unregister_player(player_id)


async def main():
    server = GameServer()
    async with websockets.serve(server.handle_client, "localhost", 8765):
        logger.info("MMO Game Server started on ws://localhost:8765")
        await asyncio.Future()


if __name__ == "__main__":
    asyncio.run(main())